snippets.campaign:
namespace = my_story

# Hidden campaign setup
my_story.0001 = {
  scope = none
  hidden = yes

  trigger = {
    current_date >= 600.1.1
    my_story_started_trigger = no
  }

  immediate = {
    add_to_global_variable_list = {
      name = my_events_happened
      target = flag:my_story_started
    }

    debug_log = "my_story.0001 — campaign started"
    debug_log_date = yes

    title:e_my_realm.holder = {
      create_story = story_my_campaign
      save_scope_as = story_owner
    }
  }
}

snippets.actor:
# Find existing actor or create fallback
immediate = {
  if = {
    limit = { character:12345 ?= { is_alive = yes } }
    character:12345 = { save_scope_as = important_actor }
  }
  else = {
    create_character = {
      template = bp1_yearly_2021_intrigue_person_template
      location = root.location
      after_creation = {
        save_scope_as = important_actor
        set_employer = root
      }
    }
  }

  scope:story = {
    set_variable = {
      name = important_actor
      value = scope:important_actor
    }
  }
}

snippets.mission:
# Send an agent to a target. Fire event on arrival.
scope:agent = {
  start_travel_plan = {
    destination = scope:story.var:first_target.capital_province
    return_trip = no
    on_arrival_event = my_story.2000
  }
}

snippets.infiltration:
my_story.2000 = {
  type = character_event
  hidden = yes
  cooldown = { days = 90 }

  trigger = {
    exists = scope:story.var:agent
    exists = scope:story.var:first_target
    scope:story.var:agent = { is_alive = yes }
  }

  immediate = {
    scope:story.var:first_target = { save_scope_as = target_ruler }
    scope:story.var:agent = { save_scope_as = agent }

    if = {
      limit = { exists = cp:councillor_spymaster }
      cp:councillor_spymaster = { save_scope_as = spymaster }

      scope:agent = {
        duel = {
          skill = intrigue
          target = scope:spymaster

          20 = {
            compare_modifier = { value = scope:duel_value multiplier = -5 }
            scope:target_ruler = {
              hard_imprison_character_effect = {
                TARGET = scope:agent
                IMPRISONER = this
              }
              trigger_event = { id = my_story.2001 days = 5 }
            }
          }

          80 = {
            compare_modifier = { value = scope:duel_value multiplier = 5 }
            scope:story = { set_variable = { name = infiltration_success value = yes } }
          }
        }
      }
    }
  }
}

snippets.cooldown:
my_story.2010 = {
  type = character_event
  hidden = yes
  cooldown = { days = 1800 }

  trigger = {
    exists = scope:story.var:investigator
    exists = scope:story.var:suspect
    scope:story.var:suspect = { is_alive = yes }
  }

  on_trigger_fail = {
    trigger_event = { id = my_story.2012 days = 2 }
  }

  immediate = {
    scope:story.var:investigator = { save_scope_as = investigator }
    scope:story.var:suspect = { save_scope_as = suspect }
    trigger_event = my_story.2011
  }
}

snippets.ending:
option = { # Canon resolution
  name = my_story.3000.a
  following_lore_path_effect = yes
  scope:key_actor = { add_character_modifier = { modifier = canon_burden years = 5 } }
}

option = { # Non-canon divergence
  name = my_story.3000.b
  following_alternate_path_effect = yes
  scope:key_actor = { add_character_flag = survived_non_canon_path }
}

snippets.transfer:
option = {
  name = my_story.4000.a
  trigger = {
    scope:new_player_character = {
      is_alive = yes
      is_playable_character = yes
      is_ai = yes
    }
  }

  show_as_tooltip = {
    set_player_character = scope:new_player_character
  }

  hidden_effect = {
    set_player_character = scope:new_player_character
  }
}

snippets.crisis:
# Main crisis event
option = {
  name = my_story.5000.a
  declare_war_on_target_effect = yes

  every_ruler = {
    if = {
      limit = { is_at_same_location = scope:crisis_owner }
      trigger_event = my_story.5001
    }
    else_if = {
      limit = { location = { geographical_region = world_eastern_kingdoms } }
      trigger_event = my_story.5002
    }
  }

  scope:target_ruler = {
    trigger_event = my_story.5003
    every_vassal_or_below = { trigger_event = my_story.5003 }
  }
}

snippets.event:
my_story.1001 = {
  type = character_event
  title = my_story.1001.title
  desc = my_story.1001.desc
  theme = intrigue

  trigger = {
    exists = scope:story
    exists = scope:story.story_owner
  }

  immediate = {
    scope:story.story_owner = { save_scope_as = story_owner }
  }

  option = {
    name = my_story.1001.a
    following_lore_path_effect = yes
  }

  option = {
    name = my_story.1001.b
    following_alternate_path_effect = yes
  }
}

snippets.registry:
scope:story = {
  set_variable = {
    name = important_actor
    value = root
  }
}

# Later:
trigger = { exists = scope:story.var:important_actor }
scope:story.var:important_actor = { save_scope_as = important_actor }

snippets.directwar:
scope:attacker = {
  start_war = {
    casus_belli = independence_war
    target = scope:defender
  }
}

snippets.factionwar:
scope:actor = {
  create_faction = {
    type = independence_faction
    target = scope:liege
  }
}

snippets.artifact:
# Store and transfer an artifact safely
scope:old_owner = {
  every_character_artifact = {
    limit = { has_variable = frostmourne }
    save_scope_as = key_artifact
  }
}

if = {
  limit = { exists = scope:key_artifact }
  scope:key_artifact = { set_owner = scope:new_owner }
}

snippets.antifarm:
if = {
  limit = { NOT = { has_character_flag = reward_already_given } }
  following_alternate_path_effect = yes
  add_character_flag = reward_already_given
}
